func:
const analystMessage = msg.payload || null;
const managerPersona = 'operations-support-manager';

if (!analystMessage || !analystMessage.message) {
  node.status({ fill: 'grey', shape: 'ring', text: '현장 분석 메시지 대기중' });
  return null;
}

const userId = analystMessage.userId || 'unknown';
const roomId = analystMessage.roomId || 'room-01';
msg.payload = {
  managerRequest: {
    managerPersona,
    systemPrompt: [
      '당신은 스마트팩토리의 운영지원전문 AI 에이전트입니다.',
      '당신의 역할은 현장 분석가 메시지를 읽고 운영 관점의 권고를 생성하는 것입니다.',
      '당신은 최종 제어를 직접 수행하지 않고, 짧은 operationCode와 관리자 메시지를 생성합니다.',
      '가능한 operationCode는 recommend-to-cool-now, recommend-to-stop, recommend-to-monitor 입니다.',
      'recommend-to-cool-now는 에어컨 조기 가동 권고를 의미합니다.',
      'recommend-to-stop은 장비 보호 목적의 조기 셧다운 권고를 의미합니다.'
    ].join(' '),
    answerFormatGuide: {
      instruction: 'managerMessage, operationCode, reason을 포함한 JSON object로 답하세요.'
    },
    userPrompt: JSON.stringify({
      task: '운영지원 권고 생성',
      fieldAnalystMessage: analystMessage
    }, null, 2)
  },
  analystMessage
};
msg.topic = `kiot/${userId}/dt/factory/${roomId}/analysis/manager/_llm-request`;
node.status({ fill: 'blue', shape: 'dot', text: '관리자 요청 생성 완료' });
return msg;

const analystMessage = msg.payload?.analystMessage || {};
const message = analystMessage.message || '';
let operationCode = null;
let managerMessage = '현재는 운영 권고를 발행하지 않고 상태만 관찰합니다.';
let reason = 'no-action-required';

const stablePhrases = [
  '매우 안정적',
  '안정 범위',
  '위험 수준은 \'Normal\'',
  '위험 수준은 "Normal"',
  '즉각적인 위험 징후는 발견되지 않았습니다',
  '현재로서는 즉각적인 위험',
  '즉시 추가 조치는 필요하지 않습니다'
];
const stopPhrases = [
  '임계 온도',
  '40도',
  '사전 셧다운',
  '장비 보호 목적',
  '선제 대응을 서둘러야'
];
const coolPhrases = [
  '경고 구간',
  '조기 대응',
  '냉각 시점을 앞당',
  '에어컨 가동 시점을 앞당',
  '즉시 냉각',
  '냉각을 시작'
];

const hasStableSignal = stablePhrases.some(phrase => message.includes(phrase));
const shouldStop = !hasStableSignal && stopPhrases.some(phrase => message.includes(phrase));
const shouldCool = !hasStableSignal && coolPhrases.some(phrase => message.includes(phrase));

if (shouldStop) {
  operationCode = 'recommend-to-stop';
  managerMessage = '장비 보호 목적상 선제 셧다운 권고가 필요합니다.';
  reason = 'preemptive-stop-near-critical-zone';
} else if (shouldCool) {
  operationCode = 'recommend-to-cool-now';
  managerMessage = '에어컨 가동 시점을 앞당겨 즉시 냉각을 시작하는 것이 좋습니다.';
  reason = 'early-cooling-recommended';
}

node.status({ fill: operationCode ? 'yellow' : 'green', shape: 'dot', text: operationCode || 'no-action' });
msg.payload = {
  llmProvider: 'manager-mock',
  llmResponse: {
    managerMessage,
    operationCode,
    reason
  },
  analystMessage
};
return msg;

const payload = msg.payload || {};
const response = payload.llmResponse || {};
const analystMessage = payload.analystMessage || {};

if (!response.managerMessage) {
  node.status({ fill: 'red', shape: 'ring', text: '관리자 응답 변환 실패' });
  return null;
}

const userId = analystMessage.userId || 'unknown';
const roomId = analystMessage.roomId || 'room-01';
const generatedAt = new Date().toISOString();

const managerMsg = {
  topic: `kiot/${userId}/dt/factory/${roomId}/analysis/manager`,
  payload: {
    userId,
    roomId,
    generatedAt,
    managerPersona: 'operations-support-manager',
    llmProvider: payload.llmProvider || 'unknown',
    message: response.managerMessage,
    operationCode: response.operationCode || null,
    reason: response.reason || 'manager-mock-generated',
    basedOnAnalystMessage: analystMessage.message || ''
  }
};

let opsMsg = null;
if (response.operationCode) {
  opsMsg = {
    topic: `kiot/${userId}/dt/factory/${roomId}/ops/recommendation`,
    payload: {
      userId,
      roomId,
      generatedAt,
      operationCode: response.operationCode,
      message: response.managerMessage,
      reason: response.reason || 'manager-mock-generated'
    }
  };
}

node.status({ fill: 'green', shape: 'dot', text: opsMsg ? 'manager/ops 발행 준비 완료' : 'manager만 발행' });
return [managerMsg, opsMsg];
